const parts = input.split(",").map(s => s.trim());

const [x, y] = parts.map(Number)

const rowText = `${("#CURSOR, ".repeat(x)).slice(0, -2)} ;\n`;
const contentText = `  ${rowText}`.repeat(y);

return `mat(\n${contentText})`;

